class Solution:
    def kthSmallest(self, matrix: List[List[int]], k: int) -> int:
        n = len(matrix)
        lo, hi = matrix[0][0], matrix[-1][-1]
        def count(x):
            i, j, c = 0, n-1, 0
            while i < n and j >= 0:
                if matrix[i][j] <= x:
                    c += j + 1; i += 1
                else:
                    j -= 1
            return c
        while lo < hi:
            mid = (lo + hi) // 2
            if count(mid) >= k: hi = mid
            else: lo = mid + 1
        return lo

