class Solution {
    int count(vector<vector<int>>& m, int x) {
        int n = m.size(), i = 0, j = n-1, c = 0;
        while (i < n && j >= 0) {
            if (m[i][j] <= x) { c += j+1; i++; }
            else j--;
        }
        return c;
    }
public:
    int kthSmallest(vector<vector<int>>& matrix, int k) {
        int lo = matrix[0][0], hi = matrix.back().back();
        while (lo < hi) {
            int mid = lo + (hi - lo) / 2;
            if (count(matrix, mid) >= k) hi = mid;
            else lo = mid + 1;
        }
        return lo;
    }
};

