int kthSmallest(int** matrix, int n, int* cs, int k) {
    int lo = matrix[0][0], hi = matrix[n-1][cs[n-1]-1];
    while (lo < hi) {
        int mid = lo + (hi - lo) / 2, c = 0, i = 0, j = n - 1;
        while (i < n && j >= 0) {
            if (matrix[i][j] <= mid) { c += j + 1; i++; }
            else j--;
        }
        if (c >= k) hi = mid; else lo = mid + 1;
    }
    return lo;
}
